/* ===== remove Butterfly page card ===== */
#page {
  background: transparent !important;
  box-shadow: none !important;
  border-radius: 0 !important;
  padding: 0 !important;
  border: none !important;
}

#page h1.page-title {
  margin-bottom: 20px !important;
}

/* ===== academic page ===== */

.academic-page {
  position: relative;
  min-height: 100vh;
  padding: 20px 0 40px;
  box-sizing: border-box;
}

.academic-layout {
  width: 100%;
  max-width: 1320px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 230px minmax(0, 1fr);
  gap: 30px;
  align-items: start;
  box-sizing: border-box;
}

.academic-left {
  position: sticky;
  top: 88px;
  display: flex;
  flex-direction: column;
  gap: 18px;
}

.academic-main {
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 22px;
}

/* ===== cards ===== */

.academic-card {
  width: 100%;
  background: rgba(255, 255, 255, 0.96);
  border-radius: 18px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.06);
  padding: 22px;
  box-sizing: border-box;
  overflow: hidden;
}

[data-theme="dark"] .academic-card {
  background: rgba(30, 30, 30, 0.92);
}

/* ===== profile ===== */

.profile-card {
  text-align: center;
  padding: 20px 16px;
}

.profile-avatar {
  width: 128px;
  height: 128px;
  display: block;
  margin: 0 auto 14px;
  object-fit: cover;
  border-radius: 12px;
  border: 4px solid #dceeff;
  background: #f6f8fc;
}

.profile-name {
  margin: 0;
  font-size: 22px;
  font-weight: 800;
  color: #24344d;
}

.profile-role {
  margin: 10px 0 8px;
  font-size: 16px;
  line-height: 1.75;
  color: #666;
}

.profile-school {
  margin-top: 10px;
  font-size: 14px;
  line-height: 1.85;
  color: #666;
}

.profile-links {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 8px;
  margin-top: 16px;
}

.profile-links a {
  display: inline-block;
  padding: 6px 13px;
  border-radius: 999px;
  background: #eef4ff;
  color: #2b5aac;
  text-decoration: none;
  font-weight: 600;
  font-size: 12px;
  transition: 0.2s;
}

.profile-links a:hover {
  transform: translateY(-2px);
}

/* ===== about / news ===== */

.about-card h2,
.news-card h2,
.paper-header h2 {
  margin: 0 0 14px;
  font-size: 30px;
  font-weight: 800;
  color: #24344d;
}

.about-card p {
  margin: 0 0 12px;
  font-size: 14px;
  line-height: 1.9;
  color: #555;
}

.news-list {
  margin: 0;
  padding-left: 18px;
}

.news-list li {
  margin-bottom: 8px;
  font-size: 14px;
  line-height: 1.8;
  color: #555;
}

.news-list span {
  font-weight: 700;
  color: #1f355b;
  margin-right: 8px;
}

/* ===== games ===== */

.game-card {
  padding: 16px 14px 18px;
}

.game-switch {
  display: flex;
  gap: 8px;
  margin-bottom: 14px;
}

.game-tab {
  flex: 1;
  border: none;
  border-radius: 999px;
  padding: 9px 0;
  background: #edf2f7;
  cursor: pointer;
  font-weight: 700;
  font-size: 13px;
  transition: 0.2s;
}

.game-tab.active {
  background: #dfefff;
  color: #2b5aac;
}

.game-panel {
  display: none;
}

.game-panel.active {
  display: block;
}

/* ===== 老虎机 ===== */

.slot-machine {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 8px;
  margin-bottom: 12px;
}

.slot-reel {
  height: 52px;
  border-radius: 12px;
  background: #f7f7fb;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 26px;
  font-weight: bold;
  box-shadow: inset 0 0 0 1px rgba(0, 0, 0, 0.06);
  position: relative;
  overflow: hidden;
  padding: 0;
  line-height: 0;
}

/* 老虎机图片：铺满格子 */
.slot-reel .game-icon-img,
.slot-reel .slot-icon-img {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  border-radius: 12px;
}

/* ===== 连连看：翻牌版 ===== */

.match-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
  margin-bottom: 14px;
}

.match-cell {
  aspect-ratio: 1 / 1;
  position: relative;
  perspective: 800px;
  cursor: pointer;
}

.match-card-inner {
  position: relative;
  width: 100%;
  height: 100%;
  transition: transform 0.45s ease, opacity 0.35s ease;
  transform-style: preserve-3d;
}

.match-cell.flipped .match-card-inner {
  transform: rotateY(180deg);
}

.match-card-face {
  position: absolute;
  inset: 0;
  border-radius: 16px;
  backface-visibility: hidden;
  overflow: hidden;
  box-shadow: inset 0 0 0 1px rgba(0, 0, 0, 0.08);
}

.match-card-front {
  background: #edf3f9;
  display: flex;
  align-items: center;
  justify-content: center;
}

.match-card-front-mark {
  width: 44%;
  height: 44%;
  border: 3px solid #c7d6e6;
  border-radius: 14px;
  position: relative;
  box-sizing: border-box;
}

.match-card-front-mark::before {
  content: "";
  position: absolute;
  inset: 16%;
  border: 3px dashed #c7d6e6;
  border-radius: 50%;
  box-sizing: border-box;
}

.match-card-back {
  background: #f7f7fb;
  transform: rotateY(180deg);
}

/* 连连看图片：翻开后铺满 */
.match-cell .game-icon-img,
.match-cell .match-icon-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.match-cell.matched {
  pointer-events: none;
}

.match-cell.matched .match-card-inner {
  opacity: 0;
}

/* ===== 通用按钮 / 提示 ===== */

.game-btn {
  width: 100%;
  border: none;
  border-radius: 14px;
  padding: 11px 0;
  background: #4c8bf5;
  color: #fff;
  font-weight: 700;
  font-size: 14px;
  cursor: pointer;
  margin-bottom: 10px;
  transition: 0.2s;
}

.game-btn:hover {
  opacity: 0.92;
}

.game-result {
  margin: 0;
  text-align: center;
  color: #666;
  font-size: 12px;
  line-height: 1.8;
}

