                     </a>`
                  : `<img src="${escapeAttribute(paper.image)}" alt="${escapeAttribute(paper.title)}">`
              }
            </div>
          `
          : "";

        return `
          <article class="paper-item">
            <div class="paper-item-inner">
              ${thumbHtml}
              <div class="paper-content">
                <div class="paper-title">${escapeHtml(paper.title || "")}</div>
